mapper.select:
SELECT s.id, s.`name`, s.id_time_zone, t.`value` AS time_zone_value, s.start_date_time, s.end_date_time, s.ac_capacity, s.dc_capacity FROM site s INNER JOIN time_zone t ON t.id = s.id_time_zone WHERE s.`status` = 1 AND s.`is_delete` = 0 AND s.id = 393 AND s.run_on_server IN
#{item}
GROUP BY s.id

SELECT EXISTS(
	SELECT 1
	FROM `alert_queue` aq
	WHERE
		aq.id_device = #{id_device}
		AND aq.id_error = #{id_error}
		AND aq.is_queue = 0
	LIMIT 1
) AS totalRecord
